document.addEventListener('DOMContentLoaded', function() {
    var fileInput = document.getElementById('file-input');
    var settingsPanel = document.getElementById('settings-panel');
    var applyBtn = document.getElementById('apply-btn');
    var resetBtn = document.getElementById('reset-btn');
    var fileList = document.getElementById('file-list');
    var progressSection = document.getElementById('progress-section');
    var progressFill = document.getElementById('progress-fill');
    var progressPercent = document.getElementById('progress-percent');
    var progressText = document.getElementById('progress-text');

    var archiveFile = null;
    var processed = false;

    function showNotification(message, isError) {
        var existing = document.querySelector('.notification');
        if (existing) existing.remove();
        var el = document.createElement('div');
        el.className = 'notification' + (isError ? ' error' : '');
        el.textContent = message;
        document.body.appendChild(el);
        setTimeout(function() { el.remove(); }, 3500);
    }

    function formatSize(bytes) {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / 1048576).toFixed(1) + ' MB';
    }

    function renderFileList() {
        if (!archiveFile) {
            fileList.innerHTML = '';
            applyBtn.disabled = true;
            settingsPanel.classList.remove('show');
            return;
        }
        settingsPanel.classList.add('show');
        applyBtn.disabled = false;
        var html = '<div class="file-item"><span class="file-name">' + archiveFile.name + '</span><span class="file-size">' + formatSize(archiveFile.size) + '</span><button class="remove-btn" id="remove-archive-btn" aria-label="Remove file"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg></button></div>';
        fileList.innerHTML = html;
        var removeBtn = document.getElementById('remove-archive-btn');
        if (removeBtn) {
            removeBtn.addEventListener('click', function() {
                archiveFile = null;
                renderFileList();
            });
        }
    }

    function showViewSection(filesList) {
        var old = document.getElementById('result-section');
        if (old) old.remove();

        var section = document.createElement('div');
        section.id = 'result-section';
        section.style.cssText = 'margin-top:var(--space-4);padding:var(--space-4);background:#f0fdf4;border:1px solid #bbf7d0;border-radius:12px;display:block';

        var html = '<div style="display:flex;align-items:center;gap:var(--space-3);margin-bottom:var(--space-3)">' +
            '<i class="fas fa-check-circle" style="color:#16a34a;font-size:1.5rem"></i>' +
            '<div><div style="font-weight:600;color:#166534">Archive Contents</div>' +
            '<div style="font-size:var(--text-sm);color:var(--color-text-light)">Found ' + filesList.length + ' file(s)</div></div></div>';

        if (filesList.length > 0) {
            html += '<div style="margin-bottom:var(--space-3)">';
            for (var i = 0; i < filesList.length; i++) {
                html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:var(--space-2);border-bottom:1px solid #e5e7eb">' +
                    '<span style="font-size:var(--text-sm);color:var(--color-text)"><i class="fas fa-file" style="margin-right:var(--space-2);color:#6b7280"></i>' + filesList[i].path + '</span>' +
                    '<span style="font-size:var(--text-sm);color:var(--color-text-light)">' + formatSize(filesList[i].size) + '</span></div>';
            }
            html += '</div>';
        } else {
            html += '<div style="padding:var(--space-3);color:var(--color-text-light);text-align:center">No files found in archive.</div>';
        }

        section.innerHTML = html;
        settingsPanel.insertBefore(section, settingsPanel.firstChild);

        applyBtn.style.display = '';
        applyBtn.innerHTML = '<i class="fas fa-eye"></i> View Again';
        applyBtn.disabled = false;
        progressSection.style.display = 'none';
        processed = true;
    }

    function loadJSZip(callback) {
        if (window.JSZip) { callback(window.JSZip); return; }
        var script = document.createElement('script');
        script.src = 'https://cdn.jsdelivr.net/npm/jszip@3.10.1/dist/jszip.min.js';
        script.onload = function() { callback(window.JSZip); };
        script.onerror = function() { showNotification('Failed to load archive library', true); };
        document.head.appendChild(script);
    }

    var dropZone = document.querySelector('.upload-area');
    if (dropZone) {
        dropZone.addEventListener('dragover', function(e) { e.preventDefault(); dropZone.style.borderColor = 'var(--color-primary)'; });
        dropZone.addEventListener('dragleave', function() { dropZone.style.borderColor = ''; });
        dropZone.addEventListener('drop', function(e) {
            e.preventDefault();
            dropZone.style.borderColor = '';
            if (e.dataTransfer.files.length) {
                archiveFile = e.dataTransfer.files[0];
                processed = false;
                var old = document.getElementById('result-section');
                if (old) old.remove();
                renderFileList();
            }
        });
    }

    fileInput.addEventListener('change', function(e) {
        if (e.target.files.length) {
            archiveFile = e.target.files[0];
            processed = false;
            var old = document.getElementById('result-section');
            if (old) old.remove();
            renderFileList();
        }
        fileInput.value = '';
    });

    applyBtn.addEventListener('click', function() {
        if (!archiveFile) return;

        var old = document.getElementById('result-section');
        if (old) old.remove();
        processed = false;

        progressSection.style.display = 'block';
        applyBtn.disabled = true;
        progressText.textContent = 'Loading library...';
        progressFill.style.width = '20%';
        progressPercent.textContent = '20%';

        loadJSZip(function(JSZip) {
            progressText.textContent = 'Reading archive...';
            progressFill.style.width = '50%';
            progressPercent.textContent = '50%';

            var reader = new FileReader();
            reader.onload = function(ev) {
                try {
                    JSZip.loadAsync(ev.target.result).then(function(zip) {
                        var filesList = [];
                        zip.forEach(function(path, entry) {
                            if (!entry.dir) {
                                filesList.push({ path: path, size: entry._data ? entry._data.uncompressedSize : 0 });
                            }
                        });

                        filesList.sort(function(a, b) { return a.path.localeCompare(b.path); });

                        progressFill.style.width = '100%';
                        progressPercent.textContent = '100%';
                        progressText.textContent = 'Done!';

                        showViewSection(filesList);
                        showNotification('Found ' + filesList.length + ' file(s) in archive');
                    }).catch(function(err) {
                        showNotification('Error reading archive: ' + err.message, true);
                        progressSection.style.display = 'none';
                        applyBtn.disabled = false;
                    });
                } catch (err) {
                    showNotification('Error reading archive: ' + err.message, true);
                    progressSection.style.display = 'none';
                    applyBtn.disabled = false;
                }
            };
            reader.readAsArrayBuffer(archiveFile);
        });
    });

    resetBtn.addEventListener('click', function() {
        archiveFile = null;
        processed = false;
        var old = document.getElementById('result-section');
        if (old) old.remove();
        renderFileList();
        progressSection.style.display = 'none';
        applyBtn.style.display = '';
        applyBtn.innerHTML = '<i class="fas fa-eye"></i> View Contents';
        applyBtn.disabled = true;
    });
});
